using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Non-static class — services are injected via constructor.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get a resource by its ID from the REST API.")]
    public async Task<string> GetResource(
        [Description("The unique identifier of the resource")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {Id}", id);
        var response = await httpClient.GetAsync($"/resources/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("List all resources, optionally filtered by a search query.")]
    public async Task<string> ListResources(
        [Description("Optional search query to filter results")] string? query = null,
        [Description("Maximum number of results to return (1-100)")] int limit = 20,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing resources (query={Query}, limit={Limit})", query, limit);
        var url = $"/resources?limit={limit}";
        if (!string.IsNullOrEmpty(query))
            url += $"&query={Uri.EscapeDataString(query)}";

        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Create a new resource with a name and optional description.")]
    public async Task<string> CreateResource(
        [Description("Name for the new resource")] string name,
        [Description("Optional description of the resource")] string? description = null,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating resource {Name}", name);
        var payload = JsonSerializer.Serialize(new { name, description }, JsonOptions);
        var content = new StringContent(payload, System.Text.Encoding.UTF8, "application/json");

        var response = await httpClient.PostAsync("/resources", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

